// src/i18n/locales/index.js
// ──────────────────────────────────────────────────────────────────────
// Bundled locale data — i18next-compatible key/value format.
//
// CRA doesn't support dynamic JSON imports from subdirectories without
// ejecting, so all 13 languages are bundled into this single module.
// When migrating to react-i18next with a proper loader, split into
// individual public/locales/{lang}/translation.json files.
//
// Add a new language by:
//   1. Adding a `const xx = {...}` object with all keys
//   2. Including `xx` in the RESOURCES export below
//
// Translation keys (46 total):
//   describe_situation, describe_problem, whats_going_on, add_details,
//    thinking, start_over, try_example, find_my_tools, try_different,
//    any_language, something_wrong, required_field, submit, loading,
//    copy, copied, print, share, reset, back, next, optional, or, and,
//    example, results, try_it, scenario_apologize, scenario_decide,
//    scenario_overwhelmed, scenario_difficult_convo,
//    scenario_unexpected_bill, scenario_medical_appt,
//    scenario_understand_complex, scenario_planning_trip,
//    wizard_placeholder, wizard_intro, wizard_finding_tools,
//    wizard_reading, wizard_your_situation, wizard_use_together,
//    best_match, tools_count_subtext, submit_shortcut_hint,
//    open_full_toolfinder, try_again
// ──────────────────────────────────────────────────────────────────────

